const config = $('System Config').first().json;

// Gather research insights
let researchData = [];
try {
  researchData = $('Read Research Insights').all().map(i => i.json);
} catch(e) {}

// Gather performance data
let perfData = [];
try {
  perfData = $('Read Last Week Performance').all().map(i => i.json);
} catch(e) {}

// Gather last week's content
let lastContent = [];
try {
  lastContent = $('Read Last Week Content').all().map(i => i.json);
} catch(e) {}

// Gather existing plans
let existingPlans = [];
try {
  existingPlans = $('Check Existing Plans').all().map(i => i.json);
} catch(e) {}

// Build context string for AI
let context = `CONTENT STRATEGY CONTEXT\n`;
context += `Week: ${config.weekNumber} (${config.weekStartDate} to ${config.weekEndDate})\n\n`;

// Research insights
context += `RESEARCH INSIGHTS (from WF-01 Intelligence):\n`;
if (researchData.length > 0) {
  for (const insight of researchData) {
    context += `- [${insight['Source Type']}] ${insight.Title} (relevance: ${insight['Relevance Score']}/10)\n`;
    if (insight.Summary) context += `  Summary: ${insight.Summary}\n`;
    if (insight['Content Opportunities']) {
      try {
        const opps = JSON.parse(insight['Content Opportunities']);
        for (const opp of opps) {
          context += `  Opportunity: ${opp.topic || opp} — ${opp.angle || ''}\n`;
        }
      } catch(e) {}
    }
  }
} else {
  context += `No research insights available this week. Use general industry knowledge.\n`;
}

// Performance data
context += `\nLAST WEEK DISTRIBUTION PERFORMANCE:\n`;
if (perfData.length > 0) {
  const successCount = perfData.filter(p => p.Status === 'Success').length;
  const failCount = perfData.filter(p => p.Status === 'Failed').length;
  const platforms = [...new Set(perfData.map(p => p.Platform))];
  context += `- Total posts: ${perfData.length} (${successCount} success, ${failCount} failed)\n`;
  context += `- Platforms used: ${platforms.join(', ')}\n`;
} else {
  context += `No distribution data from last week.\n`;
}

// Last week's content topics (to avoid repetition)
context += `\nLAST WEEK CONTENT TOPICS (avoid repeating):\n`;
if (lastContent.length > 0) {
  for (const content of lastContent.slice(0, 10)) {
    context += `- ${content.Title || 'Untitled'}\n`;
  }
} else {
  context += `No content from last week.\n`;
}

// Existing plans
const existingDates = existingPlans.map(p => p.Date).filter(Boolean);
context += `\nEXISTING PLANS THIS WEEK:\n`;
if (existingDates.length > 0) {
  context += `Already planned dates: ${existingDates.join(', ')}\n`;
  context += `Only generate content for UNPLANNED dates.\n`;
} else {
  context += `No existing plans — generate content for all 7 days.\n`;
}

return {
  json: {
    strategyContext: context,
    weekStart: config.weekStartDate,
    weekEnd: config.weekEndDate,
    existingDates: existingDates,
    researchCount: researchData.length,
    perfCount: perfData.length
  }
};

const input = $input.first().json;
const contextData = $('Build Strategy Context').first().json;
const existingDates = contextData.existingDates || [];

let strategy;
try {
  const content = input.choices[0].message.content;
  const cleaned = content
    .replace(/```json\n?/g, '')
    .replace(/```\n?/g, '')
    .trim();
  const jsonMatch = cleaned.match(/\[[\s\S]*\]/);
  strategy = JSON.parse(jsonMatch ? jsonMatch[0] : cleaned);
} catch(e) {
  // Fallback: generate basic 7-day plan
  const today = new Date();
  strategy = [];
  const fallbackTopics = [
    'How AI automation helps small businesses save time',
    'Behind the scenes: Building automated workflows',
    'Top 3 tasks every business should automate',
    'Client success story: Automation ROI',
    'The future of AI in business operations',
    'Quick tip: Automate your lead follow-up',
    'Weekly wrap-up: Automation insights'
  ];
  for (let i = 0; i < 7; i++) {
    const date = new Date(today);
    date.setDate(date.getDate() + i);
    const dateStr = date.toISOString().split('T')[0];
    strategy.push({
      date: dateStr,
      topic: fallbackTopics[i],
      content_type: 'social_post',
      platforms: ['TikTok', 'Instagram', 'Facebook'],
      brief: `Create engaging content about: ${fallbackTopics[i]}. Target SMBs interested in automation.`,
      campaign: 'General Brand Awareness'
    });
  }
}

// Filter out dates that already have plans
const filtered = strategy.filter(entry => !existingDates.includes(entry.date));

// Return each entry as a separate item for batch Airtable create
if (filtered.length === 0) {
  return { json: { message: 'All dates already planned', entries: 0 } };
}

return filtered.map(entry => ({
  json: {
    title: `${entry.date}: ${(entry.topic || '').substring(0, 50)}`,
    date: entry.date,
    contentType: entry.content_type || 'social_post',
    topic: entry.topic,
    platforms: entry.platforms || ['TikTok', 'Instagram'],
    brief: entry.brief,
    campaign: entry.campaign || 'General Brand Awareness',
    tokensUsed: (input.usage ? input.usage.total_tokens : 0)
  }
}));

const now = new Date().toLocaleString('en-ZA', { timeZone: 'Africa/Johannesburg' });
const contextData = $('Build Strategy Context').first().json;

let entries = [];
let totalTokens = 0;
try {
  entries = $('Parse Strategy').all().map(i => i.json);
  totalTokens = entries.reduce((sum, e) => sum + (e.tokensUsed || 0), 0);
} catch(e) {}

const entriesHtml = entries.map(e =>
  `<tr><td>${e.date || 'N/A'}</td><td>${e.topic || 'N/A'}</td><td>${(e.platforms || []).join(', ')}</td></tr>`
).join('\n');

const estimatedCost = (totalTokens / 1000000 * 3).toFixed(4);

return {
  json: {
    subject: `Weekly Strategy: ${entries.length} calendar entries created`,
    body: [
      '<h2>Weekly Content Strategy Report</h2>',
      `<p><strong>Date:</strong> ${now}</p>`,
      `<p><strong>Research insights used:</strong> ${contextData.researchCount || 0}</p>`,
      `<p><strong>Last week performance records:</strong> ${contextData.perfCount || 0}</p>`,
      '<hr>',
      '<h3>Content Calendar (This Week)</h3>',
      '<table border="1" cellpadding="6" style="border-collapse:collapse">',
      '<tr><th>Date</th><th>Topic</th><th>Platforms</th></tr>',
      entriesHtml || '<tr><td colspan="3">No entries created</td></tr>',
      '</table>',
      '<hr>',
      `<p><strong>Tokens Used:</strong> ${totalTokens.toLocaleString()}</p>`,
      `<p><strong>Estimated Cost:</strong> $${estimatedCost}</p>`,
      '<p>Content Calendar populated. WF-03 will generate content daily at 9:00 AM.</p>',
    ].join('\n')
  }
};
